import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  CloudDownload, Settings, ChevronLeft, Search, Loader2, 
  X, Banknote, Save, Trash2, Pencil, Plus, Download, BarChart3, QrCode, Phone, Copy, Mic, FileJson, UploadCloud,
  MessageCircle, FileSpreadsheet, ExternalLink, ChevronRight, Sparkles, Landmark, CheckCheck, Info
} from 'lucide-react';
import { exportToExcel, parseExcelFile, normalizePhoneForZalo, formatCurrency, generateVietQrUrl, normalizeString } from './utils';
import { Customer } from './types';

const parseSafe = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  const clean = String(val).replace(/[^0-9.-]/g, '');
  return parseFloat(clean) || 0;
};

const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  const amt = vol * rate;
  const bal = (amt + od) - paid;
  return {
    ...cust,
    newIndex: ni, oldIndex: oi, oldDebt: od, paid: paid,
    volume: vol, amount: amt, balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('water_data_final_v16');
    return saved ? JSON.parse(saved) : [];
  });

  const [config, setConfig] = useState(() => {
    const saved = localStorage.getItem('water_config_v16');
    let cfg = saved ? JSON.parse(saved) : { 
      waterRate: 16500, sheetUrl1: '', sheetUrl2: '', 
      bankId: 'vba', 
      accountNo: '8888942444224', accountName: 'TO TUAN KIET' 
    };

    // TỰ ĐỘNG SỬA LỖI: Nếu giá nước là 165 (legacy), đổi thành 16500
    if (cfg.waterRate === 165) {
      cfg.waterRate = 16500;
    }
    return cfg;
  });

  const [view, setView] = useState('list'); 
  const [activeTab, setActiveTab] = useState<'list1' | 'list2'>('list1');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showQr, setShowQr] = useState(false);
  const [onlyNonZalo, setOnlyNonZalo] = useState(false); 

  const [quickIndex, setQuickIndex] = useState('');
  const [paidInput, setPaidInput] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [voiceToast, setVoiceToast] = useState<{ message: string, type: 'success' | 'error' | 'info' } | null>(null);

  const [editForm, setEditForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });
  const [showAddModal, setShowAddModal] = useState(false);
  const [addForm, setAddForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollTargetId = useRef<string | null>(null);

  useEffect(() => {
    localStorage.setItem('water_data_final_v16', JSON.stringify(customers));
    localStorage.setItem('water_config_v16', JSON.stringify(config));
  }, [customers, config]);

  useEffect(() => {
    if (view === 'list' && scrollTargetId.current) {
      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('bg-yellow-100');
          setTimeout(() => el.classList.remove('bg-yellow-100'), 2000);
        }
        scrollTargetId.current = null;
      }, 300);
    }
  }, [view, customers]);

  const filtered = useMemo(() => {
    const s = searchQuery.toLowerCase().trim();
    const numericSearch = s.replace(/[^0-9]/g, '');
    const isNumeric = numericSearch.length > 0 && !isNaN(Number(numericSearch));
    const searchVal = isNumeric ? parseInt(numericSearch) : null;

    return customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      if (!isCorrectTab) return false;

      const matchText = 
        String(c.name).toLowerCase().includes(s) || 
        String(c.address).toLowerCase().includes(s) || 
        String(c.phone).includes(s) || 
        String(c.stt) === s;

      let matchAmount = false;
      if (searchVal !== null) {
        const balanceVal = Math.round(c.balance);
        if (balanceVal === searchVal) {
          matchAmount = true;
        }
      }

      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return (matchText || matchAmount) && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt);
  }, [customers, activeTab, searchQuery, onlyNonZalo]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const selectedCustomer = useMemo(() => customers.find(c => c.id === selectedId), [customers, selectedId]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    return generateVietQrUrl(config.bankId, config.accountNo, selectedCustomer.balance, selectedCustomer.name);
  }, [selectedCustomer, config]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setVoiceToast({ message, type });
    setTimeout(() => setVoiceToast(null), 3000);
  };

  const startVoiceAction = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Trình duyệt không hỗ trợ nhận diện giọng nói.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.continuous = false;
    recognition.interimResults = false;

    recognition.onstart = () => {
      setIsListening(true);
      showToast("Đang nghe: 'Tên + số + chỉ số'...", 'info');
    };

    recognition.onend = () => setIsListening(false);

    recognition.onerror = (event: any) => {
      setIsListening(false);
      showToast("Lỗi nhận diện giọng nói.", 'error');
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript.toLowerCase();
      const parts = transcript.split(/\s+số\s+/);

      if (parts.length < 2) {
        showToast("Sai cấu trúc. Hãy nói: 'Tên khách + số + chỉ số'", 'error');
        return;
      }

      const spokenName = parts[0].trim();
      const spokenIndexStr = parts[1].trim().replace(/[^0-9]/g, '');
      const spokenIndex = parseInt(spokenIndexStr);

      if (isNaN(spokenIndex)) {
        showToast("Không nhận diện được con số.", 'error');
        return;
      }

      const normalizedSpokenName = normalizeString(spokenName);
      const candidates = customers.filter(c => c.listType === activeTab);

      let bestMatch = null;
      for (const c of candidates) {
        const normalizedCustName = normalizeString(c.name);
        if (normalizedCustName.includes(normalizedSpokenName) || normalizedSpokenName.includes(normalizedCustName)) {
           bestMatch = c;
           break;
        }
      }

      if (bestMatch) {
        setCustomers(prev => prev.map(c => 
          c.id === bestMatch!.id 
            ? calculateRow({ ...c, newIndex: spokenIndex }, config.waterRate) 
            : c
        ));
        scrollTargetId.current = bestMatch.id;
        showToast(`Đã ghi: ${bestMatch.name} -> ${spokenIndex}`, 'success');
      } else {
        showToast(`Không tìm thấy: "${spokenName}"`, 'error');
      }
    };

    recognition.start();
  };

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Chưa nhập Link Cloud!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => calculateRow({
          id: `cust-${item.stt}-${activeTab}`,
          stt: parseInt(item.stt), name: item.name || `(STT ${item.stt})`,
          address: item.address || "", phone: item.phone || "",
          newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
          oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
          listType: activeTab, isZalo: !!item.isZalo
        }, config.waterRate));
        return [...other, ...mapped];
      });
      alert("Đồng bộ thành công!");
    } catch (e) { alert("Lỗi kết nối."); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        // Lọc ra các khách hàng KHÔNG thuộc Danh bộ hiện tại
        const otherTabs = prev.filter(c => c.listType !== activeTab);
        // Lấy danh sách hiện tại của Danh bộ này để gộp
        const currentTab = prev.filter(c => c.listType === activeTab);

        const mergedTab = [...currentTab];
        imported.forEach(item => {
          const idx = mergedTab.findIndex(c => c.stt === item.stt);
          if (idx !== -1) {
            // Cập nhật khách hàng cũ, đảm bảo giữ đúng ID và listType
            mergedTab[idx] = { ...mergedTab[idx], ...item, id: mergedTab[idx].id, listType: activeTab }; 
          } else {
            // Thêm mới nếu chưa có
            mergedTab.push({ ...item, listType: activeTab });
          }
        });
        return [...otherTabs, ...mergedTab];
      });
      alert(`Đã gộp thành công vào ${activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}!`);
      // Reset input file để có thể chọn lại cùng file
      e.target.value = '';
    } catch (err) { alert("Lỗi file."); } finally { setIsSyncing(false); }
  };

  const currentUsage = useMemo(() => {
    if (!selectedCustomer) return { vol: 0, amount: 0, total: 0 };
    const ni = parseSafe(quickIndex) || selectedCustomer.newIndex || 0;
    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return { vol, amount, total: amount + selectedCustomer.oldDebt };
  }, [quickIndex, selectedCustomer, config.waterRate]);

  const generateMessage = (c: Customer, qIdx?: string) => {
    const ni = parseSafe(qIdx) || c.newIndex || 0;
    const vol = (ni > 0 && ni >= c.oldIndex) ? (ni - c.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return `STT: ${c.stt}
KH: ${c.name}
SỐ: ${c.oldIndex} -> ${ni} (${vol} m³)
TIỀN: ${formatCurrency(amount)}
NỢ CŨ: ${formatCurrency(c.oldDebt)}
TỔNG: ${formatCurrency(c.balance)}
ND: TT Nuoc ${normalizeString(c.name).toUpperCase()}`;
  };

  const handleCopyMessage = (c: Customer, qIdx?: string) => {
    const msg = generateMessage(c, qIdx);
    navigator.clipboard.writeText(msg);
  };

  const openZalo = (id: string, phone: string) => {
    const cust = customers.find(c => c.id === id);
    if (cust) {
      handleCopyMessage(cust, (id === selectedId) ? quickIndex : undefined);
    }
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: true } : c));
    const normalized = normalizePhoneForZalo(phone);
    window.location.assign(normalized ? `https://zalo.me/${normalized}` : `https://zalo.me`);
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const currentIndex = filtered.findIndex(c => c.id === selectedId);
    let targetIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
    if (targetIndex >= 0 && targetIndex < filtered.length) {
      const nextCust = filtered[targetIndex];
      setSelectedId(nextCust.id);
      setQuickIndex(nextCust.newIndex > 0 ? nextCust.newIndex.toString() : "");
      setPaidInput(nextCust.paid > 0 ? nextCust.paid.toString() : "");
    }
  };

  useEffect(() => {
    if (view === 'detail' && selectedId) {
      const ni = parseSafe(quickIndex);
      const pi = parseSafe(paidInput);
      setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c));
    }
  }, [quickIndex, paidInput, view, selectedId]);

  const handleAddCustomer = () => {
    const targetStt = addForm.stt || 1;
    const newCust = calculateRow({
      id: `cust-custom-${Date.now()}`,
      ...addForm,
      listType: activeTab,
      newIndex: 0,
      paid: 0
    }, config.waterRate);

    setCustomers(prev => {
      const updated = prev.map(c => {
        if (c.listType === activeTab && c.stt >= targetStt) {
          return { ...c, stt: c.stt + 1 };
        }
        return c;
      });
      return [...updated, newCust];
    });
    setShowAddModal(false);
    setAddForm({ name: '', address: '', phone: '', stt: targetStt + 1, oldIndex: 0, oldDebt: 0, isZalo: false });
  };

  const handleSaveEdit = () => {
    if (!selectedId) return;
    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, ...editForm }, config.waterRate) : c));
    setView('detail');
  };

  const handleDeleteCustomer = () => {
    if (!selectedId) return;
    if (window.confirm("BẠN CHẮC CHẮN MUỐN XÓA KHÁCH HÀNG NÀY?")) {
      setCustomers(prev => prev.filter(c => c.id !== selectedId));
      setSelectedId(null);
      setView('list');
    }
  };

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">

      {/* Toast Voice Feedback */}
      {voiceToast && (
        <div className={`fixed top-20 left-1/2 -translate-x-1/2 z-[200] px-6 py-3 rounded-2xl shadow-2xl font-black text-sm flex items-center gap-2 animate-in fade-in zoom-in duration-300 ${
          voiceToast.type === 'success' ? 'bg-emerald-600 text-white' : 
          voiceToast.type === 'error' ? 'bg-rose-600 text-white' : 
          'bg-blue-600 text-white'
        }`}>
          {voiceToast.type === 'success' ? <CheckCheck size={18}/> : voiceToast.type === 'error' ? <X size={18}/> : <Info size={18}/>}
          {voiceToast.message}
        </div>
      )}

      {/* QR MODAL - Fixed size for better scanning */}
      {showQr && selectedCustomer && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[150] flex items-center justify-center p-6" onClick={() => setShowQr(false)}>
          <div className="bg-white rounded-[2.5rem] p-6 w-full max-w-[340px] shadow-2xl text-center flex flex-col items-center" onClick={e => e.stopPropagation()}>
            <h3 className="font-black uppercase italic text-blue-600 mb-1 text-lg">Quét Mã QR</h3>
            <p className="text-[10px] font-black text-slate-400 mb-4 uppercase truncate w-full px-4">{selectedCustomer.name}</p>

            <div className="bg-white p-2 rounded-2xl mb-4 border-2 border-slate-100 shadow-sm overflow-hidden" style={{ width: '240px', height: '240px' }}>
               <img src={qrUrl} alt="VietQR" className="w-full h-full object-contain" />
            </div>

            <div className="bg-blue-50 p-4 rounded-2xl mb-6 w-full">
               <p className="text-[9px] font-black text-blue-400 uppercase mb-0.5">Số tiền thanh toán</p>
               <p className="text-2xl font-black text-blue-700">{formatCurrency(selectedCustomer.balance)}</p>
            </div>
            <button onClick={() => setShowQr(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-lg active:scale-95">Đóng</button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full rounded-[2rem] p-6 shadow-2xl overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic">Chèn khách hàng</h2><button onClick={() => setShowAddModal(false)} className="p-2 text-slate-400"><X/></button></div>
            <div className="space-y-4">
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên khách hàng" value={addForm.name} onChange={e => setAddForm({...addForm, name: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={addForm.address} onChange={e => setAddForm({...addForm, address: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Số điện thoại" value={addForm.phone} onChange={e => setAddForm({...addForm, phone: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1"><label className="text-[10px] font-black uppercase">Chèn tại STT</label><input type="number" className="w-full bg-blue-50 p-4 rounded-xl border border-blue-200 font-bold" value={addForm.stt} onChange={e => setAddForm({...addForm, stt: parseInt(e.target.value) || 1})} /></div>
                <div className="space-y-1"><label className="text-[10px] font-black uppercase">Số cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={addForm.oldIndex} onChange={e => setAddForm({...addForm, oldIndex: parseFloat(e.target.value) || 0})} /></div>
              </div>
              <input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Nợ cũ (VNĐ - Ví dụ: 100000)" value={addForm.oldDebt} onChange={e => setAddForm({...addForm, oldDebt: parseFloat(e.target.value) || 0})} />
              <button onClick={handleAddCustomer} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-4 active:scale-95">Xác nhận chèn</button>
            </div>
          </div>
        </div>
      )}

      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase">{activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => { const max = filtered.length > 0 ? Math.max(...filtered.map(c => c.stt)) : 0; setAddForm(p => ({...p, stt: max+1})); setShowAddModal(true); }} className="p-2 text-blue-600"><Plus size={28}/></button>
              <button onClick={() => setOnlyNonZalo(!onlyNonZalo)} className={`p-2 rounded-xl relative ${onlyNonZalo ? 'text-blue-600 bg-blue-50' : 'text-slate-400'}`}>
                <MessageCircle size={22}/>
                {stats.noZalo > 0 && !onlyNonZalo && <span className="absolute -top-0.5 -right-0.5 bg-red-600 text-white text-[8px] font-black w-3.5 h-3.5 rounded-full flex items-center justify-center">{stats.noZalo}</span>}
              </button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 space-y-2">
            <div className="flex gap-2">
              <div className="relative flex-1 flex items-center">
                <div className="relative flex-1">
                   <input className="w-full bg-white rounded-xl py-3 pl-10 pr-10 shadow-sm border outline-none text-sm font-bold placeholder:text-slate-300" placeholder="Tìm tên, STT, SĐT hoặc Số tiền..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                   {searchQuery && (
                      <button onClick={() => setSearchQuery('')} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-500"><X size={14}/></button>
                   )}
                </div>
                <button 
                  onClick={startVoiceAction} 
                  className={`ml-2 p-3 rounded-xl shadow-lg border active:scale-95 transition-all duration-300 ${
                    isListening 
                      ? 'bg-rose-600 text-white border-rose-600 animate-pulse shadow-rose-200' 
                      : 'bg-white text-blue-600 border-slate-200'
                  }`}
                  title="Ghi nước bằng giọng nói: [Tên] số [Chỉ số]"
                >
                  <Mic size={20} className={isListening ? 'scale-110' : ''} />
                </button>
              </div>
              <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl shadow-sm text-blue-600 active:bg-blue-50"><BarChart3 size={20}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28 scroll-smooth">
            {filtered.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                <Search size={48} className="mb-4 opacity-20" />
                <p className="font-bold text-sm uppercase">Không tìm thấy khách hàng</p>
              </div>
            ) : filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? c.paid.toString() : ""); setView('detail'); }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all duration-500">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => {e.stopPropagation(); setCustomers(prev => prev.map(p => p.id === c.id ? {...p, isZalo: !p.isZalo} : p))}} className={`p-1.5 rounded-full border transition-all ${c.isZalo ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'text-slate-300 border-slate-100'}`}><MessageCircle size={14} /></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5">
                      <h3 className={`font-black uppercase text-[15px] truncate leading-tight ${c.isZalo ? 'text-blue-700' : 'text-slate-900'}`}>{c.name}</h3>
                      {c.newIndex > 0 && <CheckCheck size={14} className="text-emerald-600"/>}
                    </div>
                    <p className="text-[11px] text-slate-500 truncate font-bold">
