  const [addForm, setAddForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollTargetId = useRef<string | null>(null);

  useEffect(() => {
    localStorage.setItem('water_data_final_v16', JSON.stringify(customers));
    localStorage.setItem('water_config_v16', JSON.stringify(config));
  }, [customers, config]);

  useEffect(() => {
    if (view === 'list' && scrollTargetId.current) {
      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
