      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('bg-yellow-100');
          setTimeout(() => el.classList.remove('bg-yellow-100'), 2000);
        }
        scrollTargetId.current = null;
      }, 300);
    }
  }, [view, customers]);

  const filtered = useMemo(() => {
    const s = searchQuery.toLowerCase().trim();
    return customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      if (!isCorrectTab) return false;
      const matchText = 
        String(c.name).toLowerCase().includes(s) || 
        String(c.address).toLowerCase().includes(s) || 
        String(c.phone).includes(s) || 
        String(c.stt) === s;
      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return matchText && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt);
  }, [customers, activeTab, searchQuery, onlyNonZalo]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const selectedCustomer = useMemo(() => customers.find(c => c.id === selectedId), [customers, selectedId]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    return generateVietQrUrl(config.bankId, config.accountNo, selectedCustomer.balance, selectedCustomer.name);
  }, [selectedCustomer, config]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setVoiceToast({ message, type });
    setTimeout(() => setVoiceToast(null), 3000);
  };

  const startVoiceAction = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { alert("Trình duyệt không hỗ trợ."); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => { setIsListening(true); showToast("Đang nghe...", 'info'); };
    recognition.onend = () => setIsListening(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript.toLowerCase();
      const parts = transcript.split(/\s+số\s+/);
      if (parts.length < 2) { showToast("Sai: 'Tên + số + chỉ số'", 'error'); return; }
      const spokenName = parts[0].trim();
      const spokenIndexStr = parts[1].trim().replace(/[^0-9]/g, '');
      const spokenIndex = parseInt(spokenIndexStr);
      if (isNaN(spokenIndex)) { showToast("Lỗi số.", 'error'); return; }
      const normalizedSpokenName = normalizeString(spokenName);
      const candidates = customers.filter(c => c.listType === activeTab);
      let bestMatch = candidates.find(c => normalizeString(c.name).includes(normalizedSpokenName));
      if (bestMatch) {
        setCustomers(prev => prev.map(c => c.id === bestMatch!.id ? calculateRow({ ...c, newIndex: spokenIndex }, config.waterRate) : c));
        scrollTargetId.current = bestMatch.id;
        showToast(`Đã ghi: ${bestMatch.name}`, 'success');
      } else {
        showToast("Không tìm thấy khách.", 'error');
      }
    };
    recognition.start();
  };

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Chưa nhập Link Cloud!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => calculateRow({
          id: `cust-${item.stt}-${activeTab}`,
          stt: parseInt(item.stt), name: item.name || `(STT ${item.stt})`,
          address: item.address || "", phone: item.phone || "",
          newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
          oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
          listType: activeTab, isZalo: !!item.isZalo
        }, config.waterRate));
        return [...other, ...mapped];
      });
      alert("Xong!");
    } catch (e) { alert("Lỗi kết nối."); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const otherTabs = prev.filter(c => c.listType !== activeTab);
        const currentTab = prev.filter(c => c.listType === activeTab);
        const mergedTab = [...currentTab];
        imported.forEach(item => {
          const idx = mergedTab.findIndex(c => c.stt === item.stt);
          if (idx !== -1) mergedTab[idx] = { ...mergedTab[idx], ...item, id: mergedTab[idx].id, listType: activeTab }; 
          else mergedTab.push({ ...item, listType: activeTab });
        });
        return [...otherTabs, ...mergedTab];
      });
      alert(`Đã gộp vào ${activeTab === 'list1' ? 'Bộ 1' : 'Bộ 2'}`);
      e.target.value = '';
    } catch (err) { alert("Lỗi file."); } finally { setIsSyncing(false); }
  };

  const currentUsage = useMemo(() => {
    if (!selectedCustomer) return { vol: 0, amount: 0, total: 0 };
    const ni = parseSafe(quickIndex) || selectedCustomer.newIndex || 0;
    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return { vol, amount, total: amount + selectedCustomer.oldDebt };
  }, [quickIndex, selectedCustomer, config.waterRate]);

  const openZalo = (id: string, phone: string) => {
    const cust = customers.find(c => c.id === id);
    if (cust) {
      const ni = parseSafe(id === selectedId ? quickIndex : cust.newIndex);
      const vol = (ni > 0 && ni >= cust.oldIndex) ? (ni - cust.oldIndex) : 0;
      const amount = vol * config.waterRate;
      const msg = `STT: ${cust.stt}\nKH: ${cust.name}\nSỐ: ${cust.oldIndex} -> ${ni} (${vol} m³)\nTIỀN: ${formatCurrency(amount)}\nNỢ CŨ: ${formatCurrency(cust.oldDebt)}\nTỔNG: ${formatCurrency(amount + cust.oldDebt)}\nND: TT Nuoc ${normalizeString(cust.name).toUpperCase()}`;
      navigator.clipboard.writeText(msg);
    }
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: true } : c));
    window.location.assign(`https://zalo.me/${normalizePhoneForZalo(phone)}`);
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const idx = filtered.findIndex(c => c.id === selectedId);
    let target = direction === 'next' ? idx + 1 : idx - 1;
    if (target >= 0 && target < filtered.length) {
      const next = filtered[target];
      setSelectedId(next.id);
      setQuickIndex(next.newIndex > 0 ? next.newIndex.toString() : "");
      setPaidInput(next.paid > 0 ? next.paid.toString() : "");
    }
  };

  useEffect(() => {
    if (view === 'detail' && selectedId) {
      setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: parseSafe(quickIndex), paid: parseSafe(paidInput) }, config.waterRate) : c));
    }
  }, [quickIndex, paidInput, view, selectedId]);

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">

      {voiceToast && (
        <div className={`fixed top-20 left-1/2 -translate-x-1/2 z-[200] px-6 py-3 rounded-2xl shadow-2xl font-black text-sm flex items-center gap-2 animate-in fade-in zoom-in duration-300 ${
          voiceToast.type === 'success' ? 'bg-emerald-600 text-white' : 
          voiceToast.type === 'error' ? 'bg-rose-600 text-white' : 'bg-blue-600 text-white'
        }`}>
          {voiceToast.message}
        </div>
      )}

      {showQr && selectedCustomer && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[150] flex items-center justify-center p-6" onClick={() => setShowQr(false)}>
          <div className="bg-white rounded-[2.5rem] p-6 w-full max-w-[340px] shadow-2xl text-center flex flex-col items-center" onClick={e => e.stopPropagation()}>
            <h3 className="font-black uppercase italic text-blue-600 mb-1 text-lg">Quét Mã QR</h3>
            <p className="text-[10px] font-black text-slate-400 mb-4 uppercase truncate w-full px-4">{selectedCustomer.name}</p>
            <div className="bg-white p-2 rounded-2xl mb-4 border-2 border-slate-100 shadow-sm" style={{ width: '240px', height: '240px' }}>
               <img src={qrUrl} alt="QR" className="w-full h-full object-contain" />
            </div>
            <div className="bg-blue-50 p-4 rounded-2xl mb-6 w-full">
               <p className="text-[9px] font-black text-blue-400 uppercase mb-0.5">Số tiền</p>
               <p className="text-2xl font-black text-blue-700">{formatCurrency(selectedCustomer.balance)}</p>
            </div>
            <button onClick={() => setShowQr(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-lg active:scale-95">Đóng</button>
          </div>
        </div>
      )}

      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase">{activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => setOnlyNonZalo(!onlyNonZalo)} className={`p-2 rounded-xl ${onlyNonZalo ? 'text-blue-600 bg-blue-50' : 'text-slate-400'}`}><MessageCircle size={22}/></button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 space-y-2">
            <div className="flex gap-2">
              <div className="relative flex-1 flex items-center">
                <input className="w-full bg-white rounded-xl py-3 pl-10 pr-4 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                <button onClick={startVoiceAction} className={`ml-2 p-3 rounded-xl shadow-lg border active:scale-95 ${isListening ? 'bg-rose-600 text-white' : 'bg-white text-blue-600'}`}><Mic size={20} /></button>
              </div>
              <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl shadow-sm text-blue-600"><BarChart3 size={20}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? c.paid.toString() : ""); setView('detail'); }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => {e.stopPropagation(); setCustomers(prev => prev.map(p => p.id === c.id ? {...p, isZalo: !p.isZalo} : p))}} className={`p-1.5 rounded-full border ${c.isZalo ? 'bg-blue-600 text-white' : 'text-slate-300'}`}><MessageCircle size={14} /></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className={`font-black uppercase text-[15px] truncate ${c.isZalo ? 'text-blue-700' : 'text-slate-900'}`}>{c.name}</h3>
                    <p className="text-[11px] text-slate-500 truncate font-bold">{c.address || '---'}</p>
                    <div className="mt-2"><button onClick={(e) => {e.stopPropagation(); openZalo(c.id, c.phone);}} className="text-[11px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg border">ZALO / COPY</button></div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className="font-black text-[18px] text-rose-700 tracking-tighter">{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 ? <div className="text-[10px] font-black text-white bg-emerald-600 px-2 py-1 rounded-lg mt-1">MỚI: {c.newIndex}</div> : <div className="text-[10px] font-black text-slate-400 mt-1 uppercase">Chưa ghi</div>}
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md border border-slate-200 p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => setActiveTab('list1')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list1' ? 'bg-blue-600 text-white' : 'text-slate-50'}`}>Bộ 01</button>
            <button onClick={() => setActiveTab('list2')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list2' ? 'bg-blue-600 text-white' : 'text-slate-50'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="h-full bg-white flex flex-col p-4">
          <header className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-1">
              <button onClick={() => setView('list')} className="p-2 text-slate-400"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border">
                <button onClick={() => navigateDetail('prev')} className="p-2 text-slate-400"><ChevronLeft size={20}/></button>
                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => { handleCopyMessage(selectedCustomer, quickIndex); alert("Đã copy!"); }} className="p-3 bg-blue-50 text-blue-600 rounded-full border"><Copy size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl"><QrCode size={22}/></button>
            </div>
          </header>
          <div className="flex-1 space-y-4 overflow-y-auto px-2">
            <div className="border-l-4 border-blue-600 pl-4">
              <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded">STT: {selectedCustomer.stt}</span>
              <h2 className="font-black uppercase text-xl text-slate-900 leading-tight">{selectedCustomer.name}</h2>
              <p className="text-sm text-slate-500 italic">{selectedCustomer.address}</p>
            </div>
            <div className="bg-slate-50 rounded-3xl p-5 border shadow-inner text-center">
              <div className="grid grid-cols-2 gap-4">
                <div><p className="text-[10px] font-black text-slate-400 uppercase">Số cũ</p><div className="text-4xl font-black">{selectedCustomer.oldIndex}</div></div>
                <div><p className="text-[10px] font-black text-blue-600 uppercase">Số mới</p><input autoFocus type="number" className="w-full text-center text-4xl font-black text-blue-600 bg-transparent outline-none" value={quickIndex} onChange={e => setQuickIndex(e.target.value)} /></div>
              </div>
            </div>
            <div className="space-y-3 bg-white border p-5 rounded-3xl shadow-sm">
              <div className="flex justify-between font-bold text-slate-500"><span>Tiền Nước:</span><span>{formatCurrency(currentUsage.amount)}</span></div>
              <div className="flex justify-between font-bold text-rose-500"><span>Nợ cũ:</span><span>{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t pt-3 flex justify-between items-center font-black text-blue-600 text-xl"><span>TỔNG CỘNG:</span><span className="text-3xl">{formatCurrency(selectedCustomer.balance)}</span></div>
            </div>
            <div className="bg-emerald-50 rounded-3xl p-5 border border-emerald-100 text-center">
              <p className="text-[10px] font-black text-emerald-600 uppercase">Khách trả</p>
              <input type="number" className="w-full text-center text-4xl font-black text-emerald-600 bg-transparent outline-none" value={paidInput} onChange={e => setPaidInput(e.target.value)} />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 pt-4 border-t">
            <button onClick={() => { setPaidInput(selectedCustomer.balance.toString()); setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: parseSafe(quickIndex), paid: selectedCustomer.balance }, config.waterRate) : c)); scrollTargetId.current = selectedId; setView('list'); }} className="bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase active:scale-95">Thu đủ</button>
            <button onClick={() => { scrollTargetId.current = selectedId; setView('list'); }} className="bg-blue-600 text-white py-4 rounded-2xl font-black uppercase active:scale-95">Lưu & Về</button>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto">
          <header className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic text-slate-800">Cấu hình</h2><button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button></header>
          <div className="space-y-5 pb-20">
            <div className="bg-slate-50 border-2 border-dashed border-slate-200 p-6 rounded-3xl space-y-4 text-center">
              <div className="flex flex-col items-center gap-1 mb-2">
                <p className="text-[10px] font-black text-slate-400 uppercase">Danh bộ Excel hiện tại</p>
                <div className="bg-blue-600 text-white px-4 py-1.5 rounded-full font-black text-xs uppercase">{activeTab === 'list1' ? 'DANH BỘ 01' : 'DANH BỘ 02'}</div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="bg-emerald-600 text-white p-4 rounded-2xl shadow-lg font-black uppercase flex flex-col items-center gap-2"><UploadCloud size={24}/> CHỌN EXCEL</button>
                <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `Backup_${activeTab}`)} className="bg-white border-2 border-slate-200 text-slate-600 p-4 rounded-2xl font-black uppercase flex flex-col items-center gap-2"><FileSpreadsheet size={24}/> XUẤT FILE</button>
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls" onChange={handleMergeExcel} />
            </div>

            <div className="space-y-4">
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Đơn giá nước (Logic Excel - Ví dụ 165)</label><input className="w-full bg-slate-100 p-4 rounded-xl text-2xl font-black text-blue-600 outline-none" type="number" step="0.1" value={config.waterRate} onChange={e => setConfig({...config, waterRate: parseSafe(e.target.value)})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Mã Ngân hàng (Ví dụ: vba, mb, vcb...)</label><input className="w-full bg-white p-4 border rounded-xl font-black" placeholder="Mã Ngân hàng" value={config.bankId} onChange={e => setConfig({...config, bankId: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Số tài khoản</label><input className="w-full bg-white p-4 border rounded-xl font-black" placeholder="Số tài khoản" value={config.accountNo} onChange={e => setConfig({...config, accountNo: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Tên chủ tài khoản</label><input className="w-full bg-white p-4 border rounded-xl font-black uppercase" placeholder="TÊN CHỦ TÀI KHOẢN" value={config.accountName} onChange={e => setConfig({...config, accountName: e.target.value.toUpperCase()})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 1 (Script)</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="Link Bộ 1" value={config.sheetUrl1} onChange={e => setConfig({...config, sheetUrl1: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 2 (Script)</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="Link Bộ 2" value={config.sheetUrl2} onChange={e => setConfig({...config, sheetUrl2: e.target.value})} /></div>
            </div>

            <div className="pt-4 space-y-3">
              <button onClick={() => setView('list')} className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black uppercase shadow-2xl active:scale-95">Lưu & Đóng</button>
              <button onClick={() => { if(confirm("Xóa toàn bộ dữ liệu máy và cài lại?")) { localStorage.clear(); location.reload(); } }} className="w-full text-rose-500 font-black text-[10px] uppercase flex items-center justify-center gap-1 active:opacity-50">
                <Trash2 size={12}/> XÓA TOÀN BỘ DỮ LIỆU APP
              </button>
            </div>
          </div>
        </div>
      )}

      {view === 'stats' && (
        <div className="h-full bg-white flex flex-col p-6 overflow-y-auto">
          <header className="flex items-center gap-4 mb-8 shrink-0"><button onClick={() => setView('list')} className="p-2 bg-slate-50 rounded-full"><ChevronLeft size={28}/></button><h1 className="text-xl font-black uppercase italic text-slate-800">Thống kê</h1></header>
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-blue-50 p-6 rounded-3xl text-center font-black text-blue-600"><p className="text-[10px] uppercase mb-1 opacity-60">Tổng số</p><p className="text-3xl">{stats.totalCust}</p></div>
            <div className="bg-emerald-50 p-6 rounded-3xl text-center font-black text-emerald-600"><p className="text-[10px] uppercase mb-1 opacity-60">Đã ghi</p><p className="text-3xl">{stats.recorded}</p></div>
          </div>
          <div className="bg-white border-2 rounded-[2.5rem] p-6 space-y-4 shadow-sm border-slate-100">
             <div className="flex justify-between font-bold text-slate-600"><span>Tiêu thụ:</span><span>{stats.totalVol || 0} m³</span></div>
             <div className="flex justify-between font-black text-blue-600"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount || 0)}</span></div>
             <div className="flex justify-between font-bold text-rose-600"><span>Nợ cũ:</span><span>{formatCurrency(stats.totalOldDebt || 0)}</span></div>
