    if (!SpeechRecognition) { alert("Trình duyệt không hỗ trợ."); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript.toLowerCase();
      const parts = transcript.split(/\s+số\s+/);
      if (parts.length < 2) { showToast("Sai cấu trúc giọng nói.", 'error'); return; }
      const spokenName = parts[0].trim();
      const spokenIndex = parseInt(parts[1].trim().replace(/[^0-9]/g, ''));
      const candidates = customers.filter(c => c.listType === activeTab);
      let bestMatch = candidates.find(c => normalizeString(c.name).includes(normalizeString(spokenName)));
      if (bestMatch) {
        setCustomers(prev => prev.map(c => c.id === bestMatch!.id ? calculateRow({ ...c, newIndex: spokenIndex }, config.waterRate) : c));
        scrollTargetId.current = bestMatch.id;
        showToast(`Đã ghi: ${bestMatch.name}`, 'success');
