            <div className="flex gap-1">
              <button onClick={() => setShowAddModal(true)} className="p-2 text-blue-600"><Plus size={24}/></button>
              <button onClick={() => setOnlyNonZalo(!onlyNonZalo)} className={`p-2 rounded-xl ${onlyNonZalo ? 'text-blue-600 bg-blue-50' : 'text-slate-400'}`}><MessageCircle size={22}/></button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 space-y-2">
            <div className="flex gap-2">
              <div className="relative flex-1 flex items-center">
                <input className="w-full bg-white rounded-xl py-3 pl-10 pr-4 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                <button onClick={startVoiceAction} className="ml-2 p-3 rounded-xl shadow-lg border bg-white text-blue-600 active:bg-blue-600 active:text-white transition-all"><Mic size={20} /></button>
              </div>
              <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl shadow-sm text-blue-600"><BarChart3 size={20}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? (c.paid * VND_MULTIPLIER).toString() : ""); setView('detail'); }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => {e.stopPropagation(); setCustomers(prev => prev.map(p => p.id === c.id ? {...p, isZalo: !p.isZalo} : p))}} className={`p-1.5 rounded-full border ${c.isZalo ? 'bg-blue-600 text-white' : 'text-slate-300'}`}><MessageCircle size={14} /></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className={`font-black uppercase text-[15px] truncate ${c.isZalo ? 'text-blue-700' : 'text-slate-900'}`}>{c.name}</h3>
                    <div className="flex items-center gap-2">
                      <p className="text-[11px] text-slate-500 font-bold truncate">{c.address || '---'}</p>
                      {c.phone && <p className="text-[10px] text-blue-600 font-black italic">{c.phone}</p>}
                    </div>
                    <div className="mt-2">
                       <button onClick={(e) => {e.stopPropagation(); openZalo(c.id, c.phone);}} className="flex items-center gap-1.5 text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full border border-blue-200">
                          <img src="https://upload.wikimedia.org/wikipedia/commons/thumb/9/91/Icon_of_Zalo.svg/1200px-Icon_of_Zalo.svg.png" className="w-3 h-3 rounded-sm" /> ZALO / COPY
                       </button>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className="font-black text-[18px] text-rose-700 tracking-tighter">{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 ? <div className="text-[10px] font-black text-white bg-emerald-600 px-2 py-1 rounded-lg mt-1">MỚI: {c.newIndex}</div> : <div className="text-[10px] font-black text-slate-400 mt-1 uppercase">Chưa ghi</div>}
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md border border-slate-200 p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => setActiveTab('list1')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list1' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 01</button>
            <button onClick={() => setActiveTab('list2')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list2' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="h-full bg-white flex flex-col p-4 animate-in slide-in-from-right duration-200">
          <header className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-1">
              <button onClick={() => setView('list')} className="p-2 text-slate-400"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border">
                <button onClick={() => navigateDetail('prev')} className="p-2 text-slate-400"><ChevronLeft size={20}/></button>
                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => { setEditForm({ name: selectedCustomer.name, address: selectedCustomer.address, phone: selectedCustomer.phone, stt: selectedCustomer.stt, oldIndex: selectedCustomer.oldIndex, oldDebt: selectedCustomer.oldDebt, isZalo: !!selectedCustomer.isZalo }); setView('edit_customer'); }} className="p-3 bg-slate-50 rounded-full border"><Pencil size={20}/></button>
              <button onClick={() => { handleCopyMessage(selectedCustomer, quickIndex); alert("Đã copy!"); }} className="p-3 bg-blue-50 text-blue-600 rounded-full border"><Copy size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl"><QrCode size={22}/></button>
            </div>
          </header>

          <div className="flex-1 space-y-4 overflow-y-auto px-2">
            <div className="border-l-4 border-blue-600 pl-4">
              <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded">STT: {selectedCustomer.stt}</span>
              <h2 className="font-black uppercase text-xl text-slate-900 leading-tight">{selectedCustomer.name}</h2>
              <p className="text-sm text-slate-500 italic">{selectedCustomer.address}</p>
            </div>

            <div className="bg-slate-50 rounded-3xl p-5 border shadow-inner text-center">
              <div className="grid grid-cols-2 gap-4">
                <div><p className="text-[10px] font-black text-slate-400 uppercase">Số cũ</p><div className="text-4xl font-black">{selectedCustomer.oldIndex}</div></div>
                <div><p className="text-[10px] font-black text-blue-600 uppercase">Số mới</p><input autoFocus type="number" className="w-full text-center text-4xl font-black text-blue-600 bg-transparent outline-none" value={quickIndex} onChange={e => setQuickIndex(e.target.value)} /></div>
              </div>
            </div>

            <div className="space-y-3 bg-white border p-5 rounded-3xl shadow-sm">
              <div className="flex justify-between font-bold text-slate-500"><span>Tiền Nước:</span><span>{formatCurrency(selectedCustomer.amount)}</span></div>
              <div className="flex justify-between font-bold text-rose-500"><span>Nợ cũ:</span><span>{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t pt-3 flex justify-between items-center font-black text-blue-600 text-xl"><span>TỔNG CỘNG:</span><span className="text-3xl">{formatCurrency(selectedCustomer.balance)}</span></div>
            </div>

            <div className="bg-emerald-50 rounded-3xl p-5 border border-emerald-100 text-center">
              <p className="text-[10px] font-black text-emerald-600 uppercase">Khách trả (VNĐ)</p>
              <input type="number" className="w-full text-center text-4xl font-black text-emerald-600 bg-transparent outline-none" value={paidInput} placeholder="0" onChange={e => setPaidInput(e.target.value)} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 pt-4 border-t">
            <button onClick={() => { 
                const totalVnd = Math.round(selectedCustomer.balance * VND_MULTIPLIER);
                setPaidInput(totalVnd.toString()); 
                setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: parseSafe(quickIndex), paid: selectedCustomer.balance }, config.waterRate) : c)); 
                scrollTargetId.current = selectedId; setView('list'); 
            }} className="bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase active:scale-95">Thu đủ</button>
            <button onClick={() => { scrollTargetId.current = selectedId; setView('list'); }} className="bg-blue-600 text-white py-4 rounded-2xl font-black uppercase active:scale-95">Lưu & Về</button>
          </div>
        </div>
      )}

      {view === 'edit_customer' && selectedCustomer && (
        <div className="h-full bg-white p-6 animate-in slide-in-from-bottom duration-200">
          <header className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic text-slate-800">Sửa thông tin</h2><button onClick={() => setView('detail')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button></header>
          <div className="space-y-4 pb-10">
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Họ tên</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Địa chỉ</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.address || ''} onChange={e => setEditForm({...editForm, address: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Số điện thoại</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.phone || ''} onChange={e => setEditForm({...editForm, phone: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Nợ cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldDebt || 0} onChange={e => setEditForm({...editForm, oldDebt: parseFloat(e.target.value) || 0})} /></div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => { if(confirm("Xóa khách?")) { setCustomers(prev => prev.filter(c => c.id !== selectedId)); setView('list'); } }} className="bg-rose-50 text-rose-600 p-4 rounded-2xl border border-rose-100"><Trash2 size={24}/></button>
              <button onClick={handleSaveEdit} className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Lưu Thay Đổi</button>
            </div>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Cấu hình</h2><button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button></header>
          <div className="space-y-5 pb-20">
            {/* Khôi phục phần Gộp/Sao lưu Excel */}
            <div className="bg-slate-50 border-2 border-dashed border-slate-200 p-6 rounded-3xl space-y-4 text-center">
              <div className="flex flex-col items-center gap-1 mb-2">
                <p className="text-[10px] font-black text-slate-400 uppercase">Danh bộ Excel hiện tại</p>
                <div className="bg-blue-600 text-white px-4 py-1.5 rounded-full font-black text-xs uppercase">{activeTab === 'list1' ? 'DANH BỘ 01' : 'DANH BỘ 02'}</div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="bg-emerald-600 text-white p-4 rounded-2xl shadow-lg font-black uppercase flex flex-col items-center gap-2"><UploadCloud size={24}/> Gộp File</button>
                <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `Backup_${activeTab}`)} className="bg-white border-2 border-slate-200 text-slate-600 p-4 rounded-2xl font-black uppercase flex flex-col items-center gap-2"><FileSpreadsheet size={24}/> Sao lưu</button>
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls" onChange={handleMergeExcel} />
            </div>

            <div className="space-y-4">
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Đơn giá nước (Logic: 16.5 = 16.500đ)</label><input className="w-full bg-slate-100 p-4 rounded-xl text-2xl font-black text-blue-600 outline-none" type="number" step="0.1" value={config.waterRate} onChange={e => setConfig({...config, waterRate: parseSafe(e.target.value)})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Mã Ngân hàng (vba, vcb, mb...)</label><input className="w-full bg-white p-4 border rounded-xl font-black" placeholder="vba" value={config.bankId} onChange={e => setConfig({...config, bankId: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Số tài khoản</label><input className="w-full bg-white p-4 border rounded-xl font-black" placeholder="8888942444224" value={config.accountNo} onChange={e => setConfig({...config, accountNo: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Tên chủ tài khoản</label><input className="w-full bg-white p-4 border rounded-xl font-black uppercase" placeholder="TÊN CHỦ TÀI KHOẢN" value={config.accountName} onChange={e => setConfig({...config, accountName: e.target.value.toUpperCase()})} /></div>

               {/* Khôi phục 2 ô dán link cloud */}
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 1 (Script App)</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="https://script.google.com/..." value={config.sheetUrl1} onChange={e => setConfig({...config, sheetUrl1: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 2 (Script App)</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="https://script.google.com/..." value={config.sheetUrl2} onChange={e => setConfig({...config, sheetUrl2: e.target.value})} /></div>
            </div>

            <button onClick={() => setView('list')} className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black uppercase shadow-2xl active:scale-95">Lưu & Đóng</button>
            <button onClick={() => { if(confirm("Xóa dữ liệu App?")) { localStorage.clear(); location.reload(); } }} className="w-full text-rose-500 font-black text-[10px] uppercase flex items-center justify-center gap-1 mt-10"><Trash2 size={12}/> Xóa dữ liệu app</button>
          </div>
        </div>
      )}

      {view === 'stats' && (
        <div className="h-full bg-white flex flex-col p-6 animate-in slide-in-from-bottom duration-200">
          <header className="flex items-center gap-4 mb-8 shrink-0"><button onClick={() => setView('list')} className="p-2 bg-slate-50 rounded-full"><ChevronLeft size={28}/></button><h1 className="text-xl font-black uppercase italic text-slate-800">Thống kê</h1></header>
          <div className="grid grid-cols-2 gap-4 mb-6 shrink-0">
            <div className="bg-blue-50 p-6 rounded-3xl text-center font-black text-blue-600"><p className="text-[10px] uppercase mb-1 opacity-60">Tổng số</p><p className="text-3xl">{stats.totalCust}</p></div>
            <div className="bg-emerald-50 p-6 rounded-3xl text-center font-black text-emerald-600"><p className="text-[10px] uppercase mb-1 opacity-60">Đã ghi</p><p className="text-3xl">{stats.recorded}</p></div>
          </div>
          <div className="bg-white border-2 rounded-[2.5rem] p-6 space-y-4 shadow-sm flex-1 overflow-y-auto border-slate-100">
             <div className="flex justify-between font-bold text-slate-600"><span>Tiêu thụ:</span><span>{stats.totalVol || 0} m³</span></div>
             <div className="flex justify-between font-black text-blue-600"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount || 0)}</span></div>
             <div className="flex justify-between font-bold text-rose-600"><span>Nợ cũ:</span><span>{formatCurrency(stats.totalOldDebt || 0)}</span></div>
             <div className="border-t pt-2 mt-2 flex justify-between font-black text-xl italic uppercase text-slate-900"><span>TỔNG THU:</span><span>{formatCurrency((stats.totalAmount || 0) + (stats.totalOldDebt || 0))}</span></div>
          </div>
          <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `BaoCao_${activeTab}`)} className="w-full bg-blue-600 text-white py-4.5 rounded-2xl font-black uppercase shadow-xl mt-8 flex justify-center items-center gap-2">
            <Download size={20}/> Xuất file Excel
          </button>
        </div>
      )}
    </div>
  );
};

export default App;
